SELECT COUNT(*) as total_pacientes_52_100,
       MAX(numero_expediente) as ultimo_expediente,
       COUNT(DISTINCT sexo) as generos_representados
FROM perfiles_pacientes
WHERE numero_expediente LIKE 'EXP-%' AND numero_expediente >= 'EXP-00052';

